   490→      var nomePasta = sel.options[sel.selectedIndex].text;
   491→      // Primeiro busca contagem de criativos na pasta
   492→      fetch('/api/criativos/historico?folder_id=' + pid + '&limit=1')
   493→        .then(function (r) { return r.json(); })
   494→        .then(function (data) {
   495→          var n = data.total || 0;
   496→          var msg = n > 0
   497→            ? 'Deletar pasta "' + nomePasta + '"?\n' + n + ' criativo(s) serão desvinculados (não deletados).'
   498→            : 'Deletar pasta "' + nomePasta + '"? Está vazia.';
