   515→  function carregarHistorico() {
   516→    var params = '?page=' + _histPage + '&limit=20';
   517→    if (_histFiltros.folder_id) params += '&folder_id=' + _histFiltros.folder_id;
   518→    if (_histFiltros.tipo)      params += '&tipo=' + _histFiltros.tipo;
   519→    fetch('/api/criativos/historico' + params)
   520→      .then(function (r) { return r.json(); })
   521→      .then(function (data) {
   522→        var grid = document.getElementById('cri-historico-grid');
   523→        if (!grid) return;
   524→        var items = data.items || [];
   525→        if (!items.length) {
   526→          grid.innerHTML = '<div class="cri-historico-empty">Nenhum criativo salvo</div>';
   527→        } else {
   528→          grid.innerHTML = items.map(function (item) {
   529→            var thumb = item.tipo === 'video'
   530→              ? '<video class="cri-hist-thumb-video" src="' + _esc(item.url_resultado) + '" muted></video>'
   531→              : '<img class="cri-hist-thumb" src="' + _esc(item.url_resultado) + '" alt="">';
   532→            var data_fmt = item.criado_em ? item.criado_em.substring(0, 10) : '';
   533→            return '<div class="cri-hist-card" data-id="' + item.id + '">' +
   534→              thumb +
   535→              '<div class="cri-hist-info">' +
   536→              '<span class="cri-hist-modelo">' + _esc(item.modelo) + '</span>' +
   537→              '<span class="cri-hist-data">' + data_fmt + '</span>' +
   538→              '<div class="cri-hist-acoes">' +
   539→              '<button class="cri-hist-btn cri-hist-btn-dl" title="Download" data-url="' + _esc(item.url_resultado) + '" data-tipo="' + item.tipo + '">⬇</button>' +
   540→              '<button class="cri-hist-btn cri-hist-btn-pasta" title="Mover de pasta" data-id="' + item.id + '">📁</button>' +
   541→              '<button class="cri-hist-btn cri-hist-btn-del" title="Deletar" data-id="' + item.id + '">✕</button>' +
   542→              '</div></div></div>';
   543→          }).join('');
   544→          // Bind actions
   545→          grid.querySelectorAll('.cri-hist-btn-dl').forEach(function (btn) {
   546→            btn.addEventListener('click', function () {
   547→              var a = document.createElement('a');
   548→              a.href = this.dataset.url; a.download = 'criativo.' + (this.dataset.tipo === 'video' ? 'mp4' : 'webp');
   549→              a.target = '_blank'; a.click();
   550→            });
   551→          });
   552→          grid.querySelectorAll('.cri-hist-btn-del').forEach(function (btn) {
   553→            btn.addEventListener('click', function () {
   554→              if (!confirm('Deletar este criativo do histórico?')) return;
   555→              var id = this.dataset.id;
   556→              fetch('/api/criativos/historico/' + id, { method: 'DELETE' })
   557→                .then(function () { carregarHistorico(); });
   558→            });
   559→          });
   560→          grid.querySelectorAll('.cri-hist-btn-pasta').forEach(function (btn) {
   561→            btn.addEventListener('click', function () {
   562→              var id = this.dataset.id;
   563→              carregarPastas(); // garante lista atualizada
   564→              fetch('/api/criativos/pastas')
   565→                .then(function (r) { return r.json(); })
   566→                .then(function (data) {
   567→                  var opcoes = ['Sem pasta (null)'].concat((data.pastas || []).map(function (p, i) { return (i + 1) + ') ' + p.nome; }));
   568→                  var escolha = prompt('Mover para pasta:\n' + opcoes.join('\n') + '\n\nDigite 0 para sem pasta, ou o número da pasta:');
   569→                  if (escolha === null) return;
   570→                  var idx = parseInt(escolha);
   571→                  var folderId = idx === 0 ? null : ((data.pastas || [])[idx - 1] || {}).id || null;
   572→                  fetch('/api/criativos/historico/' + id + '/pasta', {
   573→                    method: 'PATCH',
   574→                    headers: { 'Content-Type': 'application/json' },
   575→                    body: JSON.stringify({ folder_id: folderId }),
   576→                  }).then(function () { carregarHistorico(); });
   577→                });
   578→            });
   579→          });
   580→        }
   581→        // Paginação
   582→        var total = data.total || 0;
   583→        var pages = data.pages || 1;
   584→        _setText('cri-pag-info', _histPage + ' / ' + pages);
   585→        var btnAnt = document.getElementById('cri-pag-anterior');
   586→        var btnPro = document.getElementById('cri-pag-proximo');
   587→        if (btnAnt) btnAnt.disabled = _histPage <= 1;
   588→        if (btnPro) btnPro.disabled = _histPage >= pages;
   589→      });
   590→  }
   591→
   592→})();
